import requests

def get_prices(sku: str, region: str):
    """Fetch both standard and AHB prices from Azure Retail Prices API."""
    url = "https://prices.azure.com/api/retail/prices"
    params = {
        "api-version": "2023-01-01-preview",
        "$filter": (
            f"serviceName eq 'Virtual Machines' "
            f"and armSkuName eq '{sku}' "
            f"and armRegionName eq '{region}' "
            f"and priceType eq 'Consumption'"
        ),
    }
    resp = requests.get(url, params=params, timeout=10)
    items = resp.json().get("Items", [])
    prices = {}
    for item in items:
        name = item.get("skuName", "")
        if "Windows" in name and "Spot" not in name and "Low Priority" not in name:
            if "Azure Hybrid Benefit" in name:
                prices["ahb"] = item["retailPrice"]
            elif "Standard" in name or "Windows" in name:
                prices["standard"] = item.get("retailPrice", 0)
    return prices

prices = get_prices("Standard_D4s_v5", "eastus")
if prices.get("standard") and prices.get("ahb"):
    savings_hr = prices["standard"] - prices["ahb"]
    savings_pct = savings_hr / prices["standard"] * 100
    print(f"Standard (license included): ${prices['standard']:.4f}/hr")
    print(f"AHB (bring your own license): ${prices['ahb']:.4f}/hr")
    print(f"Savings: ${savings_hr:.4f}/hr ({savings_pct:.1f}%)")
    print(f"Annual savings per VM (8760 hrs): ${savings_hr * 8760:.2f}")

// main.bicep — Windows VM with Azure Hybrid Benefit
param location string = resourceGroup().location
param vmName string = 'win-server-01'
param adminUsername string
@secure()
param adminPassword string

resource nic 'Microsoft.Network/networkInterfaces@2023-04-01' existing = {
  name: 'nic-${vmName}'
}

resource vm 'Microsoft.Compute/virtualMachines@2023-07-01' = {
  name: vmName
  location: location
  properties: {
    hardwareProfile: {
      vmSize: 'Standard_D4s_v5'
    }
    licenseType: 'Windows_Server'   // AHB — waives OS license cost
    storageProfile: {
      imageReference: {
        publisher: 'MicrosoftWindowsServer'
        offer: 'WindowsServer'
        sku: '2022-Datacenter'
        version: 'latest'
      }
      osDisk: {
        createOption: 'FromImage'
        managedDisk: { storageAccountType: 'Premium_LRS' }
      }
    }
    osProfile: {
      computerName: vmName
      adminUsername: adminUsername
      adminPassword: adminPassword
    }
    networkProfile: {
      networkInterfaces: [{ id: nic.id }]
    }
  }
}

// SQL Managed Instance with AHB
resource sqlMi 'Microsoft.Sql/managedInstances@2023-02-01-preview' = {
  name: 'sql-mi-prod'
  location: location
  sku: {
    name: 'GP_Gen5'
    tier: 'GeneralPurpose'
  }
  properties: {
    licenseType: 'BasePrice'        // AHB for SQL — bring your own SQL Server license
    vCores: 8
    storageSizeInGB: 256
    administratorLogin: adminUsername
    administratorLoginPassword: adminPassword
    subnetId: subnetId
  }
}

{
  "mode": "Indexed",
  "policyRule": {
    "if": {
      "allOf": [
        { "field": "type", "equals": "Microsoft.Compute/virtualMachines" },
        { "field": "Microsoft.Compute/virtualMachines/storageProfile.osDisk.osType", "equals": "Windows" },
        { "field": "Microsoft.Compute/virtualMachines/licenseType", "notEquals": "Windows_Server" }
      ]
    },
    "then": {
      "effect": "DeployIfNotExists",
      "details": {
        "type": "Microsoft.Compute/virtualMachines",
        "name": "[field('name')]",
        "roleDefinitionIds": [
          "/providers/Microsoft.Authorization/roleDefinitions/9980e02c-c2be-4d73-94e8-173b1dc7cf3c"
        ],
        "deployment": {
          "properties": {
            "mode": "incremental",
            "template": {
              "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
              "contentVersion": "1.0.0.0",
              "parameters": { "vmName": { "type": "string" } },
              "resources": [{
                "type": "Microsoft.Compute/virtualMachines",
                "apiVersion": "2023-07-01",
                "name": "[parameters('vmName')]",
                "location": "[resourceGroup().location]",
                "properties": { "licenseType": "Windows_Server" }
              }]
            },
            "parameters": { "vmName": { "value": "[field('name')]" } }
          }
        }
      }
    }
  }
}
